def solve(*args, **kwargs):
    # Extract parameters from kwargs
    include_components = kwargs.get('includeComponents', False)
    limit = kwargs.get('limit', None)
    difficulty_filter = kwargs.get('difficulty', None)
    tag_filter = kwargs.get('tag', None)
    problems = kwargs.get('problems', [])

    # Apply filters: difficulty and tag
    filtered = []
    for p in problems:
        if difficulty_filter is not None and p.get('difficulty') != difficulty_filter:
            continue
        if tag_filter is not None:
            tags = p.get('tags', [])
            if tag_filter not in tags:
                continue
        filtered.append(p)

    # Apply limit
    if limit is not None:
        filtered = filtered[:limit]

    # Prepare metadata counts if includeComponents is true
    metadata = {}
    if include_components:
        component_language_totals = {}
        component_status_totals = {}

        for p in filtered:
            # Count languages
            lang = p.get('language')
            if lang:
                component_language_totals[lang] = component_language_totals.get(lang, 0) + 1

            # Count status
            status = p.get('status')
            if status:
                component_status_totals[status] = component_status_totals.get(status, 0) + 1

        metadata['componentLanguageTotals'] = component_language_totals
        metadata['componentStatusTotals'] = component_status_totals

    # Return the filtered problems and metadata
    return {
        'problems': filtered,
        'metadata': metadata
    }
